// ===== VINTEO — extendDeadlineDirect (inlined so it can't silently fail to load) =====
(function () {
  async function waitMs(ms) { return new Promise(function (r) { setTimeout(r, ms); }); }
  async function findTabOnOrigin(origin) {
    try { var tabs = await chrome.tabs.query({ url: origin + '/*' }); if (tabs && tabs.length > 0) return tabs[0]; } catch (e) {}
    return null;
  }
  async function createHiddenTab(origin) { return await chrome.tabs.create({ url: origin + '/', active: false }); }
  async function waitForTabReady(tabId, targetOrigin, maxMs) {
    var deadline = Date.now() + (maxMs || 20000);
    while (Date.now() < deadline) {
      try {
        var tab = await chrome.tabs.get(tabId);
        var isRefresh = tab.url && tab.url.indexOf('/session-refresh') !== -1;
        var isComplete = tab.status === 'complete';
        var isOnOrigin = tab.url && tab.url.indexOf(targetOrigin) === 0;
        if (isComplete && isOnOrigin && !isRefresh) { await waitMs(600); return tab; }
      } catch (e) { return null; }
      await waitMs(400);
    }
    return null;
  }
  async function sendVintedFetchToTab(tabId, path, method, body) {
    try {
      var resp = await chrome.tabs.sendMessage(tabId, { _vinteoApi: true, action: 'vintedFetch', url: path, method: method, body: body });
      return resp || { success: false, error: 'No response' };
    } catch (e) { return { success: false, error: e && e.message ? e.message : 'sendMessage failed' }; }
  }
  async function extendDeadlineDirect(params) {
    var origin = params.origin || '';
    var shipmentId = params.shipmentId;
    var days = params.days;
    var reason = params.reason;
    if (!origin || !/^https:\/\/[a-z0-9.-]+\.vinted\.[a-z]{2,3}$/i.test(origin)) return { success: false, error: 'origin invalide: ' + String(origin) };
    if (!shipmentId) return { success: false, error: 'shipmentId manquant' };
    if (!reason || !String(reason).trim()) return { success: false, error: 'raison manquante' };
    var existingTab = await findTabOnOrigin(origin);
    var tab = existingTab;
    var weCreatedIt = false;
    if (!tab) {
      try { tab = await createHiddenTab(origin); weCreatedIt = true; }
      catch (e) { return { success: false, error: 'Impossible de creer un onglet : ' + (e && e.message) }; }
      var ready = await waitForTabReady(tab.id, origin, 25000);
      if (!ready) {
        try { await chrome.tabs.remove(tab.id); } catch (e) {}
        return { success: false, error: "L'onglet " + origin + " n'a pas pu charger (session expiree ? reessaie apres t'etre reconnecte a ce compte)." };
      }
    }
    var path = '/api/v2/shipments/' + encodeURIComponent(String(shipmentId)) + '/deadline_extension';
    var body = JSON.stringify({ deadline_extension: { key: String(days || '3'), reason: String(reason || '') } });
    var res = await sendVintedFetchToTab(tab.id, path, 'POST', body);
    if (weCreatedIt) { try { await chrome.tabs.remove(tab.id); } catch (e) {} }
    if (res.success) return { success: true, data: res.data || {} };
    var status = res.status;
    var data = res.data;
    var msg = (data && (data.message || data.error || data.detail)) || res.error || (status ? 'HTTP ' + status : 'Erreur Vinted');
    return { success: false, error: msg, status: status };
  }
  function safeRun(params, sendResponse) {
    var responded = false;
    function respondOnce(payload) { if (responded) return; responded = true; try { sendResponse(payload); } catch (e) {} }
    var killTimer = setTimeout(function () { respondOnce({ success: false, error: 'Timeout global (50s)' }); }, 50000);
    extendDeadlineDirect(params).then(function (result) { clearTimeout(killTimer); respondOnce(result); })
      .catch(function (err) { clearTimeout(killTimer); respondOnce({ success: false, error: (err && err.message) ? err.message : 'Erreur interne' }); });
  }
  function handleMessage(msg, sender, sendResponse) {
    if (!msg || msg.action !== 'extendDeadlineDirect') return false;
    safeRun({ origin: msg.origin || '', shipmentId: msg.shipmentId, days: msg.days, reason: msg.reason }, sendResponse);
    return true;
  }
  try { chrome.runtime.onMessage.addListener(handleMessage); } catch (e) {}
  try {
    chrome.runtime.onMessageExternal.addListener(function (msg, sender, sendResponse) {
      var url = (sender && sender.url) || '';
      var allowed = url.startsWith('https://vinteo.xyz') || url.startsWith('http://localhost:3001');
      if (!allowed) return false;
      return handleMessage(msg, sender, sendResponse);
    });
  } catch (e) {}
  try { self._vinteoExtendDeadlineDirect = extendDeadlineDirect; } catch (e) {}
  try { self.__vinteoEDDBulletproof = extendDeadlineDirect; } catch (e) {}
  try { globalThis._vinteoExtendDeadlineDirect = extendDeadlineDirect; } catch (e) {}
})();
// ===== VINTEO — fetchDressingPage (single-page streaming) =====
// Lets the frontend fire pages 2..N in parallel AFTER page 1 is displayed.
(function () {
  async function _vinteoFindVintedTab(origin) {
    try {
      if (origin) {
        var tabs = await chrome.tabs.query({ url: origin + '/*' });
        if (tabs && tabs.length > 0) {
          for (var i = 0; i < tabs.length; i++) if (tabs[i].status === 'complete') return tabs[i];
          return tabs[0];
        }
      }
      var tabs2 = await chrome.tabs.query({ url: 'https://*.vinted.*/*' });
      if (tabs2 && tabs2.length > 0) return tabs2[0];
    } catch (e) {}
    return null;
  }
  async function _vinteoVintedGet(origin, path) {
    var tab = await _vinteoFindVintedTab(origin);
    if (!tab) return { success: false, error: 'No Vinted tab open' };
    try {
      var resp = await chrome.tabs.sendMessage(tab.id, { _vinteoApi: true, action: 'vintedFetch', url: path, method: 'GET' });
      return resp || { success: false, error: 'No response from content script' };
    } catch (e) {
      return { success: false, error: (e && e.message) ? e.message : 'sendMessage failed' };
    }
  }
  async function fetchDressingPage(params) {
    var origin = (params && params.origin) || '';
    var cond = (params && params.cond) || '';
    var page = Number(params && params.page) || 1;
    if (page < 1) page = 1;
    var userResp = await _vinteoVintedGet(origin, '/api/v2/users/current');
    if (!userResp.success) return { success: false, error: 'Profil inaccessible (' + (userResp.error || '') + ')' };
    var user = userResp.data && (userResp.data.user || userResp.data) || {};
    var userId = String(user.id || '');
    if (!userId) return { success: false, error: 'User ID introuvable' };
    var url = '/api/v2/wardrobe/' + userId + '/items?per_page=96&page=' + page + '&order=relevance' + (cond ? '&cond=' + encodeURIComponent(cond) : '');
    var resp = await _vinteoVintedGet(origin, url);
    if (!resp.success) return { success: false, error: 'HTTP ' + (resp.status || 'error'), status: resp.status };
    var items = (resp.data && resp.data.items) || [];
    var pagination = (resp.data && resp.data.pagination) || {};
    var totalPages = Number(pagination.total_pages) || null;
    var totalEntries = Number(pagination.total_entries) || null;
    return {
      success: true, items: items, userId: userId, login: user.login || '',
      origin: origin, page: page, totalPages: totalPages, totalEntries: totalEntries,
      hasMore: totalPages ? page < totalPages : (items.length >= 96),
    };
  }
  try { self._vinteoFetchDressingPage = fetchDressingPage; } catch (e) {}
  try {
    chrome.runtime.onMessage.addListener(function (msg, sender, sendResponse) {
      if (!msg || msg.action !== 'fetchDressingPage') return false;
      fetchDressingPage({ origin: msg.origin, cond: msg.cond, page: msg.page })
        .then(function (r) { try { sendResponse(r); } catch (e) {} })
        .catch(function (e) { try { sendResponse({ success: false, error: (e && e.message) ? e.message : 'fetchDressingPage error' }); } catch (_) {} });
      return true;
    });
  } catch (e) {}
  try {
    chrome.runtime.onMessageExternal.addListener(function (msg, sender, sendResponse) {
      var url = (sender && sender.url) || '';
      var allowed = url.startsWith('https://vinteo.xyz') || url.startsWith('http://localhost:3001');
      if (!allowed) return false;
      if (!msg || msg.action !== 'fetchDressingPage') return false;
      fetchDressingPage({ origin: msg.origin, cond: msg.cond, page: msg.page })
        .then(function (r) { try { sendResponse(r); } catch (e) {} })
        .catch(function (e) { try { sendResponse({ success: false, error: (e && e.message) ? e.message : 'fetchDressingPage error' }); } catch (_) {} });
      return true;
    });
  } catch (e) {}
})();
